sparql:
SELECT ?nation ?ranking WHERE {
  ?nation wdt:P1344 wd:Q28494721 .
  ?nation wdt:P1352 ?ranking .
  ?nation rdfs:label ?label .
  FILTER(CONTAINS(STR(?label) , "Puerto Rico"))
}

SELECT ?athlete ?medalMonth WHERE {
  ?athlete wdt:P2522 ?championship .
  ?athlete wdt:P2869 ?worldRecord .
  ?championship wdt:P166 ?medal .
  ?medal wd:Q18358861 ?month .
}

SELECT ?jockey ?race WHERE {
  wd:Q17015440 wdt:P1352 ?rank .
  ?jockey wdt:P5317 wd:Q17015440 .
  ?jockey wdt:P1346 ?race
}

SELECT ?song ?inception WHERE {
  ?song rdfs:label "Start Again" @en .
  ?song wdt:P571 ?inception .
  FILTER(CONTAINS(STR(?inception) , "2016"))
}

SELECT ?player WHERE {
  ?player wdt:P1618 ?jerseyNumber .
  ?player wdt:P118 wd:Q238593 .
  ?player wdt:P118 wd:Q13361030
}

SELECT ?radioStation WHERE {
  ?radioStation wdt:P463 wd:Q497568 .
