}

SELECT ?city(str(?pop) AS ?population) WHERE {
  ?city wdt:P1082 ?pop .
  FILTER(?city = wd:Q1645)
}

SELECT ?shoppingMall WHERE {
  wd:Q1686 wdt:P1082 ?population .
