}

SELECT ?event WHERE {
  ?athlete wdt:P1300 wd:Q9672 .
  ?athlete wdt:P1355 '19' .
  ?athlete wdt:P641 ?event .
  FILTER(CONTAINS(STR(?event) , 'cross-country skiing') || CONTAINS(STR(?event) , 'cross country skiing'))
}

SELECT ?person ?votes WHERE {
  ?person wdt:P3602 ?election .
